import React, { useState } from "react";
import "./EMR.css";

export default function EMR() {
  const [tab, setTab] = useState("notes");

  const [patient, setPatient] = useState({
    name: "",
    age: "",
    gender: "",
    mrn: "",
    visitId: "",
    department: "",
    photo: null
  });

  const [vitals, setVitals] = useState({
    hr: "",
    sys: "",
    dia: "",
    rr: "",
    spo2: "",
    temp: ""
  });

  const [redFlags, setRedFlags] = useState({
    chestPain: false,
    hypoxia: false,
    trauma: false,
    seizure: false
  });

  const [triage, setTriage] = useState("");
  const [nurse, setNurse] = useState("");

  // ================= AI LOGIC =================
  const aiLevel = () => {
    if (vitals.spo2 && vitals.spo2 < 90) return "LEVEL 1 – EMERGENT";
    if (vitals.hr && vitals.hr > 130) return "LEVEL 1 – EMERGENT";
    if (vitals.temp && vitals.temp > 39) return "LEVEL 2 – EMERGENCY";
    return "LEVEL 3 – URGENT";
  };

  return (
    <div className="emr-wrapper">

      {/* ================= HEADER ================= */}
      <div className="emr-header">
        <div className="profile">
          <label>
            <input
              type="file"
              hidden
              accept="image/*"
              onChange={(e) =>
                setPatient({ ...patient, photo: URL.createObjectURL(e.target.files[0]) })
              }
            />
            <img
              src={patient.photo || ""}
              alt="patient"
            />
          </label>

          <div>
            <input placeholder="Patient Name" />
            <div className="sub">
              <input placeholder="Age" />
              <input placeholder="Gender" />
            </div>
          </div>
        </div>

      </div>

      {/* ================= VISIT INFO ================= */}
      <div className="visit-strip">
        <input placeholder="MRN" />
        <input placeholder="Visit ID" />
        <input placeholder="Department" />
      </div>

      {/* ================= TABS ================= */}
      <div className="tabs">
        <button
          className={tab === "notes" ? "active" : ""}
          onClick={() => setTab("notes")}
        >
          Clinical Notes
        </button>

        <button
          className={tab === "vitals" ? "active" : ""}
          onClick={() => setTab("vitals")}
        >
          Vitals
        </button>
      </div>

      {/* ================= CLINICAL NOTES ================= */}
      {tab === "notes" && (
        <div className="card">
          <label>Chief Complaint</label>
          <input />

          <label>History of Present Illness</label>
          <textarea />

          <label>Assessment</label>
          <textarea />

          <label>Plan</label>
          <textarea />
        </div>
      )}

      {/* ================= VITALS ================= */}
      {tab === "vitals" && (
        <div className="card">

          <h3>Vital Signs</h3>

          <div className="grid">
            <input placeholder="Heart Rate()" onChange={e => setVitals({ ...vitals, hr: e.target.value })} />
            <input placeholder="BP Systolic" onChange={e => setVitals({ ...vitals, sys: e.target.value })} />
            <input placeholder="BP Diastolic" onChange={e => setVitals({ ...vitals, dia: e.target.value })} />
            <input placeholder="Respiratory Rate" onChange={e => setVitals({ ...vitals, rr: e.target.value })} />
            <input placeholder="SpO₂ %" onChange={e => setVitals({ ...vitals, spo2: e.target.value })} />
            <input placeholder="Temperature °C" onChange={e => setVitals({ ...vitals, temp: e.target.value })} />
          </div>

          {/* ===== RED FLAGS ===== */}
          <h3>Red Flags Detected</h3>
          <div className="checks">
            {Object.keys(redFlags).map((key) => (
              <label key={key}>
                <input
                  type="checkbox"
                  checked={redFlags[key]}
                  onChange={() =>
                    setRedFlags({ ...redFlags, [key]: !redFlags[key] })
                  }
                />
                {key}
              </label>
            ))}
          </div>

          {/* ===== AI LEVEL ===== */}
          <div className="ai-box">
            <h3>AI Suggested Level</h3>
            <strong>{aiLevel()}</strong>
          </div>

          {/* ===== TRIAGE ===== */}
          <h3>Triage Level</h3>
          <div className="triage">
            {["Level 1", "Level 2", "Level 3", "Level 4", "Level 5"].map(l => (
              <button
                key={l}
                className={triage === l ? "active" : ""}
                onClick={() => setTriage(l)}
              >
                {l}
              </button>
            ))}
          </div>

          {/* ===== ISOLATION ===== */}
          <h3>Isolation</h3>
          <div className="checks">
            <label><input type="checkbox" /> Droplet</label>
            <label><input type="checkbox" /> Contact</label>
            <label><input type="checkbox" /> None</label>
          </div>

          {/* ===== NURSE ===== */}
          <label>Nurse Name</label>
          <input value={nurse} onChange={(e) => setNurse(e.target.value)} />

        </div>
      )}

      {/* ================= FOOTER ================= */}
      <div className="footer-btns">
        <button className="draft">Save Draft</button>
        <button className="complete">Complete Visit</button>
      </div>
    </div>
  );
}
